  private void saveProject() {
    // essential for project migrations to update the list of migrations run to the disk, however, suitable also for language migrations
    // although we used to do project.save(), I see no point, MPS stuff (like, set of modules) doesn't change, all we care
    // about AFAIK is persistence of project components' state.
    Project project = mySession.getProject();
    // Looks like starting from IDEA 2023.3 following code should be executed
    // outside of IDEA write action.
    if (project instanceof MPSProject) {
      com.intellij.openapi.project.Project ijProject = ((MPSProject) project).getProject();
      // ij does not save the project in headless which is not acceptable for us, copying the ij internals
      StoreUtil.saveSettings(ijProject, false);
    }

  }

  private Status runCleanupMigrations(final ProgressMonitor m) {
    int cleanupStepsCount = projectStepsCount(true);
    if (cleanupStepsCount == 0) {
      return new Status.OK("Nothing to do");
    }
    m.start("Cleaning...", cleanupStepsCount);
    final AtomicReference<Status> result = new AtomicReference<>(new Status.ERROR("Not executed"));
    final AtomicBoolean activity = new AtomicBoolean(false);
    addGlobalLabel(mySession.getProject(), "Cleanup started");
    mySession.getProject().getComponent(ClassLoaderManager.class).runNonReloadableSection(new Runnable() {
      @Override
      public void run() {
        do {
          MigrationRunnable pm = mySession.nextStepCleanup();
          if (pm == null) {
            result.set(Status.NO_ERRORS);
            break;
          }

          m.step(pm.getDescription());
          Status executeSingleStep = executeSingleStep(m, pm.getDescription(), pm);
          activity.set(true);
          if (!(executeSingleStep.isOk())) {
            result.set(executeSingleStep);
            break;
          }

          m.advance(1);
        } while (true);
      }
    });
    addGlobalLabel(mySession.getProject(), "Cleanup finished");
    m.done();

    if (activity.get()) {
      refreshScriptInstances();
    }
    return result.get();
  }

