  private void runForceSave(final ProgressMonitor m) {
    final Project project = mySession.getProject();
    final String caption = "Force-saving project modules, models...";
    try {
      // HACK. Give IDEA wizard (when we run this task from IDE) a chance to complete wizard page initialization.
      // w/o this sleep, invokeAndWait freezes UI update and previous step UI is there, which is very confusing
      Thread.sleep(500);
    } catch (Exception ex) {
      // ignore
    }
    runLocalHistoryRecord(caption, () -> ApplicationManager.getApplication().invokeAndWait(() -> project.getRepository().getModelAccess().runWriteAction(() -> {
      List<SModule> allModules = project.getProjectModulesWithGenerators();
      m.start(caption, ListSequence.fromList(allModules).count() + 10);
      for (AbstractModule module : ListSequence.fromList(allModules).ofType(AbstractModule.class)) {
        module.forceSaveRecursively();
        m.advance(1);
      }
    })));
    m.done();
  }

  public void runLocalHistoryRecord(String caption, Runnable r) {
    assert myCurrentChange == null;
    myCurrentChange = LocalHistory.getInstance().startAction(caption);
    try {
      r.run();
    } finally {
      myCurrentChange.finish();
      myCurrentChange = null;
    }
  }

  private Status runProjectMigrations(final ProgressMonitor m) {
    m.start("Running project migrations...", projectStepsCount(false));
    // I like status approach of runCleanupMigrations() better; telling blank "success" vs "not executed" gives 
    // more information. But left close to the original code for now
    final AtomicReference<Status> success = new AtomicReference<>(Status.NO_ERRORS);
    final AtomicBoolean activity = new AtomicBoolean(false);
    mySession.getProject().getComponent(ClassLoaderManager.class).runNonReloadableSection(new Runnable() {
      @Override
      public void run() {
        while (true) {
          MigrationRunnable pm = mySession.nextStepProject();
          if (pm == null) {
            break;
          }

          m.step(pm.getDescription());
          Status executeSingleStep = executeSingleStep(m, pm.getDescription(), pm);
          activity.set(true);
          if (!(executeSingleStep.isOk())) {
            success.set(executeSingleStep);
            break;
          }

          m.advance(1);
        }
      }
    });
    m.done();
    if (activity.get()) {
      refreshScriptInstances();
    }

    return success.get();
  }

  private Status runLanguageMigrations(final ProgressMonitor m) {
    m.start("Running language migrations...", moduleStepsCount());
    final AtomicReference<Status> success = new AtomicReference<>(Status.NO_ERRORS);
    final AtomicBoolean activity = new AtomicBoolean(false);

    // FIXME why non-reloadable section when we don't compile any module here and can't deploy anything?
    //     perhaps, as fixed module could let some language complete its deps and make it loadable?
    //     Anyway, need to figure out better approach as the method is deprecated
    mySession.getProject().getComponent(ClassLoaderManager.class).runNonReloadableSection(new Runnable() {
      @Override
      public void run() {
        while (true) {
          final MigrationRunnable sa = mySession.nextStepModule();
          if (sa == null) {
            break;
          }

          m.step(sa.getDescription());
          Status executeSingleStep = executeSingleStep(m, sa.getDescription(), sa);
          activity.set(true);
          if (!(executeSingleStep.isOk())) {
            success.set(executeSingleStep);
            break;
          }

          m.advance(1);
        }
      }
    });
    m.done();
    if (activity.get()) {
      refreshScriptInstances();
    }

    return success.get();
  }

  private boolean findNotMigrated(ProgressMonitor m) {
    final Wrappers._boolean haveNotMigrated = new Wrappers._boolean(false);
    // FIXME each time we use checker from within a session, it can take already executed migrations internally
    //      the only scenario to address is use of MigrationCheckerImpl independently
    mySession.getChecker().findNotMigrated(m, mySession.getExecutedModuleMigrations(), new Processor<Problem>() {
      public boolean process(Problem p) {
        haveNotMigrated.value = true;
        return false;
      }
    });
    return haveNotMigrated.value;
  }

  private int moduleStepsCount() {
    // FIXME see MigrationSessionBase.nextStepModule for use of PM initialized with this value. we report 1 unit for each executed ScriptApplied, which is
    //      one per module x script x version, that's why I go with non-distinct affected modules here. However, it's not effective
    return CollectionSequence.fromCollection(mySession.getModuleMigrations()).translate((it) -> it.affectedModules()).count();
  }

  private int projectStepsCount(boolean isCleanup) {
    Iterable<ProjectMigration> migrations = mySession.getProjectMigrations();
    int cleanupSize = Sequence.fromIterable(migrations).ofType(CleanupProjectMigration.class).count();
    return (isCleanup ? cleanupSize : Sequence.fromIterable(migrations).count() - cleanupSize);
  }
